import "server-only";

import { Redis } from "@upstash/redis";

export const redis = Redis.fromEnv();

export async function pingRedis() {
  return redis.ping();
}

import "server-only";

import { Ratelimit } from "@upstash/ratelimit";
import { Redis } from "@upstash/redis";

export const apiRatelimit = new Ratelimit({
  redis: Redis.fromEnv(),
  limiter: Ratelimit.slidingWindow(60, "1 m"),
  analytics: true,
  prefix: "stackfoundry:api",
});

import { NextResponse } from "next/server";

import { pingRedis } from "@/lib/upstash/redis";

export async function GET() {
  const pong = await pingRedis();
  return NextResponse.json({ ok: pong === "PONG" });
}

const deployChecks = [
  "Create the vendor project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function UpstashRedisPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Upstash Redis</h1>
        <p className="text-muted-foreground">Serverless Redis for rate limits, cache, queues, and resumable state.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
